#include <vector>

class ChessBoard {
public:
    ChessBoard() {}

    void draw() {
        // Draw chessboard
        glBegin(GL_QUADS);
        for (int i = 0; i < 8; i++) {
            for (int j = 0; j < 8; j++) {
                if ((i + j) % 2 == 0) {
                    glColor3f(0.1f, 0.1f, 0.1f);
                } else {
                    glColor3f(0.7f, 0.7f, 0.7f);
                }
                glVertex3f(i * 2 - 8, j * 2 - 8, 0);
                glVertex3f(i * 2 - 8, j * 2 - 6, 0);
                glVertex3f(i * 2, j * 2 - 6, 0);
                glVertex3f(i * 2, j * 2 - 8, 0);
            }
        }
        glEnd();
    }

    void drawPieces() {
        // Draw chess pieces
        glBegin(GL_TRIANGLES);
        glColor3f(1.0f, 0.0f, 0.0f); // Red
        glVertex3f(-1, -1, 0);
        glVertex3f(-1, 1, 0);
        glVertex3f(1, 0, 0);
        glEnd();

        glBegin(GL_TRIANGLES);
        glColor3f(0.0f, 1.0f, 0.0f); // Green
        glVertex3f(1, -1, 0);
        glVertex3f(1, 1, 0);
        glVertex3f(-1, 0, 0);
        glEnd();
    }
};
