class HashMap<K, V> {
  private _map: { [key: string]: V };
  private _size: number;

  constructor() {
    this._map = {};
    this._size = 0;
  }

  // Add a key-value pair to the hash map
  set(key: K, value: V): void {
    this._map[this._hash(key)] = value;
    this._size++;
  }

  // Get the value associated with a key
  get(key: K): V | undefined {
    return this._map[this._hash(key)];
  }

  // Remove a key-value pair from the hash map
  delete(key: K): void {
    delete this._map[this._hash(key)];
    this._size--;
  }

  // Hash function using modulo to map to an index
  private _hash(key: K): string {
    return key.toString() + Math.floor(Math.random() * 1000000);
  }
}
