 *
 * @param str The string to reverse.
 * @returns The reversed string.
 */
function reverseString(str: string): string {
  let result = "";
  let left = 0;
  let right = str.length - 1;

  while (left < right) {
    result += str[right];
    left++;
    right--;
  }

  return result;
}
