#include  <msp430.h>

// Configure the watchdog timer to generate a software interrupt
WDTCTL = WDTPW | WDTHOLD;

// Set the clock to 16 MHz
BCSCTL3 |= LFXT1S_2; // Set the clock source to DCO
DCOCTL = DCOX_3 | DCOF;
BCSCTL1 |= DCO7;

// Configure the internal 2.5V voltage reference
VLOCTL = 0; // Select internal reference
VLOCTL |= VLOEN; // Enable internal reference

// Set up the temperature sensor
TEMPCTL = TEMPSRC_0 | TEMPSRCEN; // Select internal reference and enable temperature sensor
TEMPCTL |= TEMPAVG_2; // Select average temperature

int main(void)
{
    WDTCTL = WDTPW | WDTHOLD; // Stop the watchdog timer

    // Wait for the temperature sensor to settle
    while (TEMPSTAT & TEMPSYN) {}

    // Read the temperature
    int16_t temp = TEMPS;

    // Convert the temperature to Celsius
    float temperature = (float) temp * 25.0 - 250;

    // Print the temperature
    UARTprintf("Temperature: %d.%d C\r\n", (int)(temperature / 100), (int)(temperature % 100));

    // Infinite loop to prevent the watchdog timer from resetting the device
    while (1)
    {
        // Wait for a software interrupt
        __bis_SR_register(CPUOFF | GIE);
    }

    return 0;
}
```

This code assumes that the UART module is already configured and available for printing the temperature value. If the UART module is not configured, you will need to add code to set it up.

